const API_URL = "http://localhost:8080/api/ventas"; // <--- REVISA QUE TENGA EL /api/

export const registrarVenta = async (datosVenta) => {
    try {
        const response = await fetch(API_URL, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(datosVenta)
        });
        
        // Si el servidor responde 404 o 500, esto atrapará el error
        if (!response.ok) {
            const errorData = await response.json();
            console.error("Error del servidor:", errorData);
            return null;
        }
        
        return await response.json(); // Esto activa el window.print() en tu página
    } catch (error) {
        console.error("Error de conexión:", error);
        return null;
    }
};
